// I2C Configuration

/// I2C bus frequency in Hz (400kHz - Fast Mode)
pub const I2C_FREQUENCY: u32 = 400_000;

// I2C Pin Assignments

/// I2C0 SDA (Data) pin
pub const I2C_SDA_PIN: u8 = 0;

/// I2C0 SCL (Clock) pin
pub const I2C_SCL_PIN: u8 = 1;

// SPI Configuration

/// SPI bus frequency in Hz
/// Shared bus limit is the BMP390 altimeter at 10 MHz max — using 8 MHz for margin
pub const SPI_FREQUENCY: u32 = 8_000_000;

// SPI Pin Assignments

/// SPI0 MISO (Master In, Slave Out) pin
pub const SPI_MISO_PIN: u8 = 4;

/// SPI0 CS (Chip Select) pin for Altimeter
pub const ALTIMETER_CS_PIN: u8 = 7;

/// SPI0 CS (Chip Select) pin for Flash
pub const FLASH_CS_PIN: u8 = 6;

/// SPI0 CLK (Clock) pin
pub const SPI_CLK_PIN: u8 = 2;

/// SPI0 MOSI (Master Out, Slave In) pin
pub const SPI_MOSI_PIN: u8 = 3;

// UART Configuration

/// UART1 baudrate for RFD900x radio (115200 baud, 8N1)
pub const UART_BAUDRATE: u32 = 115200;

// UART Pin Assignments

/// UART1 TX (Transmit) pin for RFD900x radio
pub const UART_TX_PIN: u8 = 8;

/// UART1 RX (Receive) pin for RFD900x radio
pub const UART_RX_PIN: u8 = 9;

// GPIO Pin Assignments

/// Onboard LED pin
pub const LED_PIN: u8 = 25;

// Actuator Pin Assignments (put actual pin numbers when testing)
pub const SSA_DROGUE_PIN: u8 = 36;
pub const SSA_MAIN_PIN: u8 = 39;
pub const BUZZER_PIN: u8 = 21;
pub const MAV_PIN: u8 = 40;
pub const SV_PIN: u8 = 47;

// Timing Configuration

/// Main loop cycle time in milliseconds
pub const MAIN_LOOP_DELAY_MS: u64 = 50; // 20 Hz

/// Maximum allowed time for one execute() call before logging an overrun warning
pub const LOOP_BUDGET_MS: u64 = 100;

/// Hardware watchdog timeout in milliseconds
/// = LOOP_BUDGET_MS (100) + 20 ms for Embassy I2C/SPI async overhead.
/// A second feed() after execute() covers the MAIN_LOOP_DELAY_MS sleep,
/// so the watchdog only ever fires if execute() itself hangs
pub const WATCHDOG_TIMEOUT_MS: u32 = 120;

/// Stall duration used by test_watchdog to deliberately trigger the watchdog
/// Must be > WATCHDOG_TIMEOUT_MS so the chip resets during the stall.
pub const WATCHDOG_TEST_STALL_MS: u64 = 200;

pub const FLASH_LOGGING_PERIOD_MS: u64 = 50;   // Fast record rate: 20 Hz
pub const FULL_LOGGING_PERIOD_MS:  u64 = 1000; // Full record rate:  1 Hz
pub const SNAPSHOT_LOGGING_PERIOD_MS: u64 = 200; // Snapshot ring rate: 5 Hz

// I²C/SPI timeouts: if a bus transaction hangs (e.g. GPS NACK holds SDA low),
// bail out instead of blocking the flight loop forever.
/// Per-cycle sensor read timeout (BMP390, GPS, IMU, ADC).
pub const SENSOR_READ_TIMEOUT_MS: u64 = 30;
/// QSPI flash op timeout (erase/program can be legitimately slow).
pub const FLASH_TIMEOUT_MS: u64 = 200;
/// Snapshot ring scan timeout: 1024 slots × ~0.3ms/read = up to ~400ms at slow SPI speeds.
pub const SNAPSHOT_SCAN_TIMEOUT_MS: u64 = 2_000;
/// Full-flash wipe timeout. 14 MB / 4 KB sectors = up to 3584 sectors; W25Q128JV
/// typical sector erase is ~45ms, max ~400ms — allow 5 minutes to be safe.
pub const FLASH_WIPE_TIMEOUT_MS: u64 = 300_000;
/// One-time driver init timeout (happens once at boot, be generous).
pub const SENSOR_INIT_TIMEOUT_MS: u64 = 500;

// USB Logger Configuration

/// USB logger ring buffer size in bytes
pub const USB_LOGGER_BUFFER_SIZE: usize = 4096;

// Flight Logic Thresholds
pub const ARMING_ALTITUDE: f32 = 100.0; // Altitude in meters to arm parachutes (Placeholder)

// Pressure Validity Thresholds (Pa)
// 80 kPa (~2000m) to 120 kPa (~ -1400m) covers reasonable ground operation range
pub const PRESSURE_MIN_PA: f32 = 80_000.0;
pub const PRESSURE_MAX_PA: f32 = 120_000.0;

pub const ALT_SAMPLE_INTERVAL: u32 = 10;

pub const MAIN_DEPLOY_DELAY_MS: u64 = 1000; // talk to R&P to find this exact number

pub const MAIN_DEPLOY_ALTITUDE_FT: f32 = 2000.0;

/// L3: Y-axis acceleration (g) launch-detect threshold.
/// 10-sample moving average crossing this triggers Standby → Ascent.
pub const LAUNCH_ACCEL_Y_THRESHOLD_G: f32 = 4.0;
/// 1 g in m/s² (LSM6DSOX accel is in m/s²).
pub const G_TO_MS2: f32 = 9.80665;

/// L3: BLiMS landing-zone targets (degrees). Hard-coded; no ground command.
/// Both upwind and downwind phases aim for the same landing zone.
pub const BLIMS_TARGET_LAT: f32 = 42.446610;
pub const BLIMS_TARGET_LON: f32 = -76.461304;
pub const BLIMS_UPWIND_LAT: f32 = BLIMS_TARGET_LAT;
pub const BLIMS_UPWIND_LON: f32 = BLIMS_TARGET_LON;
pub const BLIMS_DOWNWIND_LAT: f32 = BLIMS_TARGET_LAT;
pub const BLIMS_DOWNWIND_LON: f32 = BLIMS_TARGET_LON;
/// Surface wind direction (degrees FROM, 0=N, 90=E). Used when no altitude profile is set.
pub const BLIMS_WIND_FROM_DEG: f32 = 45.0;

pub const MAIN_LOG_TIMEOUT_MS: u64 = 1_200_000; // 20 minutes

/// Minimum altitude (m AGL) the rocket must exceed before the N2 velocity
/// check is armed. Prevents false triggers during early coast.
pub const N2_ARM_ALTITUDE_M: f32 = 500.0;

pub const UMBILICAL_TIMEOUT_MS: u64 = 15_000; // 15 seconds

/// Maximum age of the most recent umbilical heartbeat (`<H>`) before the link
/// is considered down. Independent of `UMBILICAL_TIMEOUT_MS`, which gates the
/// vent-on-disconnect action.
pub const HEARTBEAT_TIMEOUT_MS: u64 = 5_000; // 5 s — 3 s was too tight for USB CDC jitter
pub const MAV_OPEN_DURATION_MS: u64 = 3500; // 4 seconds for L3 - 7.88 for LV - 12 for Wet Dress
pub const LAUNCH_SV_PREVENT_MS: u64 = 2_000;  // 2 s SV open before closing
pub const LAUNCH_SV_TO_MAV_WAIT_MS: u64 = 1_000; // 1 s wait between SV close and MAV open
pub const SSA_THRESHOLD_MS: u64 = 1000; // Duration to fire ematch

